  "https://bassinoimpex.com/cdn/shop/files/BPB-742_512x512.jpg?v=1757590883",
  "https://images.openai.com/thumbnails/url/ZjfvBHicDclJDoIwFADQEyFGiAyJMSiTMipGDBtjC0oLlOkjyqm8jrfRt33fTw7Q9CrPZwx37waylAPE5rNHDzcgeIbriu_zumkIe6zb1f9UzU8VCx9oF-_L7gVCOGXCeTTlqDjlMeWssCXlAsQTqpVqgSVmOYjEI91OnpxIl0GkbRSaxhN5qDADp3xtytFuzbsfJDZ1j7reG4OvKNFwcAttvKLdXreXopvGwJ5erf0A63I_Xg",
  "https://images.openai.com/static-rsc-1/A3A-XQvvK7bbDbkcwn6Oriptyzrr7DPuCau6bq1bIBjcAmOMbIk_l6e3rw1AHNQTLKY4ZzzS4qMwO4cQ07xnZEXhw7D3hxs2x7GfOeDr6DAsxeRiqiWr_x3KPvU-1NFIJwxcqCnX1_wBThZF43ekww",
  "https://images.openai.com/static-rsc-1/H3rMIqcZ9JBFsRyGM8Ig40t8K-2uezJU4meRvIODpG-Uorfpm4I8K8bUUbE6RA5GhiNXw5nsElVGD5zAJIh_imTTEEv28rRHFWnxJdooJP8h4jJ0mKma1YAyuNp3i28KXI6xYyFpKMGQxD1xYG3IQQ",
  "https://m.media-amazon.com/images/I/317PqKGP1CL._AC_UF1000%2C1000_QL80_.jpg",
  "https://images.openai.com/thumbnails/url/_H50Y3icDclJDoIwAADAFwF1QyAxpgQlYixLEAMXAi07QqVFlEf5H3-jc53vp-ScMk2Ssg4Pb8ozIvC0A2LBeMIrLOL-LrGyp7Tqiv1j9z8NIqKa2LPdCPk5zH2_bhOZIj00wAUSlQ5lZDDgHO_shcdNJZzDarUl1gI1MFUCECbPKziPjpf2pcuFWjabbhnIOrwF8bSeZWK2aZbYeB6bE3MOb8-0bJqzqVVQFP8AA54-FA",
  "https://www.simplexfurniture.in/uploaded-files/product-images/Laboratory-Sinks.1713530378.jpg",
  "https://image.made-in-china.com/202f0j00DebWjHZKbpYT/Luxury-Design-Black-Color-Floor-Standing-Wash-Basin-Sink-Wc-Bathroom-Pedestal-Basin-for-Hotle-or-Hosehold.webp",
  "https://image.made-in-china.com/2f0j00ISTlQNnqJtGP/Factory-Price-Pedestal-Basin-Black-Funnel-Shaped-Basin-One-Piece-Bathroom-Free-Standing-Pedestal-Sink-Hand-Wash-Basin-for-Hotel.webp",
  "https://www.inart.co.in/cdn/shop/files/71hv9D1snOL.jpg?v=1773470985&width=360",
  "https://m.media-amazon.com/images/I/510SkLiw7fL._AC_UF1000%2C1000_QL80_.jpg",
  "https://images.unsplash.com/photo-1596495578065-6e0763fa1178?auto=format&fit=crop&w=1000&q=80"
];

const categories = [
  'bowl-basin',
  'wall-hung-full-pedestal',
  'wall-hung-half-pedestal',
  'wall-hung-no-pedestal',
  'integrated-basin',
  'countertop-basin',
  'below-counter-basin',
  'pedestals',
  'lab-sink',
  'freestanding-basin'
];

export default function BasinCollection() {
  const { categoryId } = useParams();
  const { cart, addToCart, removeFromCart, updateQuantity, setIsSidebarOpen, getProductMin, getProductStep } = useCart();

  const catIndex = categories.indexOf(categoryId);
  
  if (catIndex === -1) {
    return <Navigate to="/basin" />;
  }

  const getProducts = () => {
    const defaultPrices = [2499, 3299, 4199, 5499, 8999];
    const defaultMRPs = [3499, 4499, 5999, 7499, 12999];
    const startIndex = catIndex * 5;
    
    // Create a beautiful properly cased title from category id
    const fmtTitle = categoryId.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
    
    return [0, 1, 2, 3, 4].map((i) => ({
      id: `${categoryId}-${i+1}`,
      name: `Premium ${fmtTitle} - Model 0${i+1}`,
      description: `Experience the elegant and modern design perfectly tailored for your luxury bathroom. Built with extreme precision.`,
      price: defaultPrices[i],
      mrp: defaultMRPs[i],
      image: imageUrls[startIndex + i],
      rating: 4.5 + (i * 0.1),
      reviews: 120 + (i * 35)
    }));
  };

  const products = getProducts();

  return (
    <div 
      className="min-h-screen font-sans w-full overflow-y-auto bg-transparent"
    >
        {/* Ambient Top Glow */}
        <div className="absolute top-0 inset-x-0 h-[400px] bg-gradient-to-b from-[#A68966]/10 to-transparent pointer-events-none"></div>
      {/* Glassmorphic Header */}
      <header className="bg-white/40 backdrop-blur-md h-[70px] flex items-center justify-between px-6 text-gray-900 sticky top-0 z-50 border-b border-gray-200/50 shadow-sm transition-all duration-300">
        <div className="flex items-center gap-4">
          <Link to="/basin" className="hover:text-gray-600 transition-colors p-2 rounded-full hover:bg-gray-100">
            <ArrowLeft className="w-6 h-6" />
          </Link>
          <h1 className="text-lg md:text-xl font-bold tracking-tight">{categoryId.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ')}</h1>
        </div>
        <div className="relative flex items-center cursor-pointer p-2 rounded-full hover:bg-gray-100 transition-colors" onClick={() => setIsSidebarOpen(true)}>
          <ShoppingCart className="w-7 h-7 text-gray-700" />
          {cart.length > 0 && (
            <span className="absolute top-0 right-0 bg-[#E33939] text-white font-bold text-[10px] rounded-full w-[18px] h-[18px] flex items-center justify-center shadow-md">
              {cart.length}
            </span>
          )}
        </div>
      </header>

      <main className="max-w-[1400px] mx-auto p-4 md:p-8 pb-16 mt-4 relative z-10">
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 xl:gap-8 justify-center">
          {products.map((product, i) => {
            const cartItem = cart.find(item => item.product.id === product.id);
            return (
              <motion.div 
                key={product.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.4, delay: i * 0.1 }}
                className="bg-white rounded-[28px] p-3 shadow-sm hover:shadow-lg flex flex-col transition-all duration-300 border border-gray-100/50"
              >
                {/* Image Container */}
                <div className="relative w-full h-[260px] rounded-[20px] overflow-hidden bg-gray-50 flex items-center justify-center mb-1 group">
                  <img 
                    src={product.image} 
                    alt={product.name} 
                    className="h-full w-full object-cover transition-transform duration-700 group-hover:scale-[1.03]"
                  />
                  
                  {/* Dynamic Badges */}
                  <div className="absolute top-3 left-3 bg-white/95 backdrop-blur-md text-[#222222] text-[12px] font-bold px-3 py-1.5 rounded-full flex items-center gap-1.5 shadow-[0_2px_8px_rgba(0,0,0,0.08)]">
                    <Star className="w-[12px] h-[12px] fill-[#F5A623] text-[#F5A623]" /> Prime Pick
                  </div>

                  {/* Dot Indicators */}
                  <div className="absolute bottom-3 inset-x-0 flex justify-center gap-1.5">
                    <div className="w-[6px] h-[6px] rounded-full bg-white"></div>
                    <div className="w-[6px] h-[6px] rounded-full bg-white/50"></div>
                    <div className="w-[6px] h-[6px] rounded-full bg-white/50"></div>
                    <div className="w-[6px] h-[6px] rounded-full bg-white/50"></div>
                  </div>
                </div>

                {/* Content Container */}
                <div className="px-2 pt-4 pb-2 flex flex-col flex-grow">
                  {/* Price Row */}
                  <div className="flex items-baseline gap-2 mb-1">
                    <span className="text-[22px] font-extrabold text-[#111111] tracking-tight">
                      Γé╣{product.price.toLocaleString('en-IN')}
                    </span>
                    <span className="text-[13px] text-gray-500 font-medium tracking-wide">
                      List price
                    </span>
                  </div>

                  {/* Title Row */}
                  <h2 className="text-[15px] font-medium text-[#222222] leading-snug truncate whitespace-nowrap overflow-hidden text-ellipsis mb-5">
                    <span className="font-bold">{product.name.split(' ')[0]}</span> ΓÇó {product.name.substring(product.name.indexOf(' ') + 1) || product.description}
                  </h2>
                  
                  <div className="h-[1px] w-full bg-gray-100 mb-4"></div>
                  
                  {/* Specs Row */}
                  <div className="flex items-center text-[13px] text-gray-600 font-medium mb-4">
                    <div className="flex flex-1 items-center justify-center gap-2 border-r border-gray-100">
                      <Star className="w-[16px] h-[16px] text-gray-400" />
                      <span>{product.rating} Rating</span>
                    </div>
                    <div className="flex flex-1 items-center justify-center gap-2">
                      <svg className="w-[16px] h-[16px] text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" /></svg>
                      <span>1 Unit</span>
                    </div>
                  </div>

                  <div className="h-[1px] w-full bg-gray-100 mb-4"></div>

                  <div className="flex items-center justify-between text-[13px] text-gray-500 mb-6">
                    <div>By ΓÇó <span className="text-gray-900 font-semibold underline underline-offset-2">Parryware</span></div>
                    <div>2 days ago</div>
                  </div>

                  {/* Buttons */}
                  <div className="mt-auto">
                    {cartItem ? (
                      <div className="w-full h-[52px] flex items-center justify-between border-[1px] border-gray-800 rounded-full overflow-hidden bg-white text-gray-900 shadow-sm">
                        <button 
                          onClick={() => {
                            if (cartItem.quantity <= getProductMin(product)) {
                              removeFromCart(product.id);
                            } else {
                              updateQuantity(product.id, cartItem.quantity - getProductStep(product));
                            }
                          }}
                          className="h-full px-5 hover:bg-gray-100 transition-colors flex items-center justify-center"
                        >
                          {cartItem.quantity <= getProductMin(product) ? 
                            <Trash2 className="w-[18px] h-[18px]" strokeWidth={2} /> : 
                            <Minus className="w-[18px] h-[18px]" strokeWidth={2.5} />
                          }
                        </button>
                        <span className="font-bold text-[16px] px-4">{cartItem.quantity}</span>
                        <button 
                          onClick={() => updateQuantity(product.id, cartItem.quantity + getProductStep(product))} 
                          className="h-full px-5 bg-gray-50 hover:bg-gray-100 transition-colors flex items-center justify-center border-l border-gray-200"
                        >
                          <Plus className="w-[20px] h-[20px]" strokeWidth={2.5} />
                        </button>
                      </div>
                    ) : (
                      <button
                        onClick={() => addToCart(product)}
                        className="w-full h-[52px] rounded-full text-[15px] font-semibold tracking-wide transition-all duration-300 flex items-center justify-center gap-2 bg-gradient-to-b from-[#2a2a2a] to-[#0f0f0f] text-white shadow-md transform hover:scale-[1.01]"
                      >
                        Add to Cart
                      </button>
                    )}
                  </div>
                </div>
              </motion.div>
            );
          })}
        </div>
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { ShoppingCart, Star, Check, ArrowLeft, Trash2, Plus, Minus } from 'lucide-react';
import { Link } from 'react-router-dom';
import { useProducts } from '../context/ProductContext';

export default function CardinalCollection() {
  const { products } = useProducts();
  const [cart, setCart] = useState([]);

  const handleAddToCart = (product) => {
    if (!cart.find(item => item.product.id === product.id)) {
      setCart([...cart, { product, quantity: 1 }]);
    }
  };

  const handleIncrease = (productId) => {
    setCart(cart.map(item => 
      item.product.id === productId ? { ...item, quantity: item.quantity + 1 } : item
    ));
  };

  const handleDecrease = (productId) => {
    setCart(cart.map(item => {
      if (item.product.id === productId) {
        if (item.quantity === 1) return null;
        return { ...item, quantity: item.quantity - 1 };
      }
      return item;
    }).filter(Boolean));
  };

  const handleRemoveFromCart = (productId) => {
    setCart(cart.filter(item => item.product.id !== productId));
  };


  return (
    <div 
      className="min-h-screen font-sans w-full overflow-y-auto bg-transparent relative"
    >
      {/* Ambient Top Glow */}
      <div className="absolute top-0 inset-x-0 h-[400px] bg-gradient-to-b from-[#A68966]/10 to-transparent pointer-events-none"></div>
      {/* Amazon Style Header */}
      {/* Glassmorphic Header */}
      <header className="bg-white/40 backdrop-blur-md h-[60px] flex items-center justify-between px-4 text-gray-900 sticky top-0 z-50 shadow-sm border-b border-gray-200/30">
        <div className="flex items-center gap-4">
          <Link to="/faucets" className="hover:text-gray-300">
            <ArrowLeft className="w-6 h-6" />
          </Link>
        </div>
        <div className="relative flex items-center cursor-pointer">
          <ShoppingCart className="w-8 h-8" />
          {cart.length > 0 && (
            <span className="absolute -top-2 -right-2 bg-[#F08804] text-black font-bold text-xs rounded-full w-5 h-5 flex items-center justify-center">
              {cart.reduce((total, item) => total + item.quantity, 0)}
            </span>
          )}
        </div>
      </header>

      <main className="max-w-[1400px] mx-auto p-4 md:p-6 pb-12 mt-4">
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          {products.map((product) => {
            const cartItem = cart.find(item => item.product.id === product.id);
            return (
              <motion.div 
                key={product.id}
                whileHover={{ y: -4 }}
                transition={{ duration: 0.2 }}
                className="bg-white rounded-[24px] p-3 shadow-[0_8px_24px_rgba(0,0,0,0.04)] hover:shadow-[0_12px_32px_rgba(0,0,0,0.08)] flex flex-col transition-all duration-300 border border-gray-100"
              >
                {/* Image Container */}
                <div className="relative w-full h-[220px] rounded-[16px] overflow-hidden bg-[#F8F9FA] flex items-center justify-center mb-4">
                  <img 
                    src={product.image} 
                    alt={product.name} 
                    className="max-h-full max-w-full object-contain mix-blend-multiply p-4"
                  />
                  {/* Dynamic Tags assigned via Admin Portal */}
                  {product.tags && product.tags.length > 0 ? (
                    <div className="absolute top-3 inset-x-3 flex flex-col gap-2 pointer-events-none">
                      {product.tags.map(tag => (
                        <div key={tag} className="self-start text-[11px] font-bold px-2.5 py-1.5 rounded-full flex items-center gap-1.5 shadow-sm border bg-[#FFF8E6]/95 backdrop-blur-md text-[#F5A623] border-[#FFEDCC]">
                          <Star className="w-[10px] h-[10px] fill-[#F5A623]" /> {tag}
                        </div>
                      ))}
                    </div>
                  ) : null}
                </div>

                {/* Content Container */}
                <div className="px-1 flex flex-col flex-grow">
                  {/* Price Row */}
                  <div className="flex items-baseline gap-2 mb-1.5">
                    <span className="text-[22px] font-extrabold text-[#111111] tracking-tight">
                      Γé╣{product.price.toLocaleString('en-IN')}
                    </span>
                    <span className="text-[13px] text-gray-500 font-medium tracking-wide">
                      M.R.P: <span className="line-through">Γé╣{product.mrp.toLocaleString('en-IN')}</span>
                    </span>
                  </div>

                  {/* Title Row */}
                  <h2 className="text-[14px] font-medium text-gray-600 leading-snug line-clamp-2">
                    <span className="font-bold text-gray-800">{product.name.split(' ')[0]}</span> ΓÇó {product.name.substring(product.name.indexOf(' ') + 1) || product.description}
                  </h2>
                  
                  <div className="h-[1px] w-full bg-gray-100 my-4"></div>
                  
                  {/* Specs Row & Variants */}
                  <div className="flex flex-col gap-3">
                    <div className="flex items-center gap-4 text-[13px] text-gray-700 font-medium">
                      <div className="flex items-center gap-1.5 bg-gray-50 px-2 py-1 rounded-md border border-gray-100">
                        <Star className="w-[14px] h-[14px] text-gray-400" />
                        {product.rating} <span className="text-gray-400 font-normal">Rating</span>
                      </div>
                      <div className="flex items-center gap-1.5 bg-gray-50 px-2 py-1 rounded-md border border-gray-100">
                        <Check className="w-[14px] h-[14px] text-gray-400" />
                        {product.reviews} <span className="text-gray-400 font-normal">Reviews</span>
                      </div>
                    </div>
                    {product.variants && product.variants.length > 0 && (
                      <div className="flex flex-wrap gap-2 mt-2">
                        {product.variants.map((v, i) => (
                          <span key={i} className="text-[10px] font-bold border border-gray-200 bg-gray-50 rounded px-2 py-1 text-gray-600">
                            {v.key}: <span className="text-gray-800">{v.value}</span>
                          </span>
                        ))}
                      </div>
                    )}
                  </div>
                  
                  <div className="h-[1px] w-full bg-gray-100 my-4"></div>
                  
                  {/* Footer Row */}
                  <div className="flex items-center justify-between text-[12px] text-gray-500 mb-5 font-medium">
                    <div>By ΓÇó <span className="text-gray-800 font-semibold underline underline-offset-2">Parryware</span></div>
                    <div className="text-emerald-600 font-semibold px-2 py-0.5 bg-emerald-50 rounded border border-emerald-100 shadow-sm text-[11px] flex items-center gap-1">In Stock</div>
                  </div>

                  {/* Buttons */}
                  <div className="mt-auto">
                    {cartItem ? (
                      <div className="w-full h-[48px] flex items-center justify-between border-[1.5px] border-[#2A2A2A] rounded-full overflow-hidden bg-white shadow-sm transition-all text-[#0F1111]">
                        <button 
                          onClick={() => cartItem.quantity === 1 ? handleRemoveFromCart(product.id) : handleDecrease(product.id)} 
                          className="h-full px-5 hover:bg-gray-100 transition-colors flex items-center justify-center text-[#0F1111]"
                        >
                          {cartItem.quantity === 1 ? 
                            <Trash2 className="w-[18px] h-[18px]" strokeWidth={2} /> : 
                            <Minus className="w-[18px] h-[18px]" strokeWidth={2.5} />
                          }
                        </button>
                        <span className="font-bold text-[16px] px-4">{cartItem.quantity}</span>
                        <button 
                          onClick={() => handleIncrease(product.id)} 
                          className="h-full px-5 bg-[#F6F6F6] hover:bg-[#EAEAEA] transition-colors flex items-center justify-center text-[#0F1111] border-l border-gray-200"
                        >
                          <Plus className="w-[20px] h-[20px]" strokeWidth={2.5} />
                        </button>
                      </div>
                    ) : (
                      <button
                        onClick={() => handleAddToCart(product)}
                        className="w-full h-[48px] rounded-full text-[15px] font-semibold transition-all duration-200 flex items-center justify-center gap-2 bg-gradient-to-b from-[#333333] to-[#111111] hover:from-[#222222] hover:to-[#000000] text-white shadow-[0_4px_12px_rgba(0,0,0,0.15)] hover:shadow-[0_6px_16px_rgba(0,0,0,0.2)] transform hover:-translate-y-[1px] active:translate-y-0"
                      >
                        Add to Cart
                      </button>
                    )}
                  </div>
                </div>
              </motion.div>
            );
          })}
        </div>
      </main>
    </div>
  );
}

import React from 'react';
import { X, Trash2, Plus, Minus, ShoppingCart, CheckCircle2, ShoppingBag, ArrowRight } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Link, useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';

const CartSidebar = () => {
  const {
    cart,
    isSidebarOpen,
    setIsSidebarOpen,
    removeFromCart,
    updateQuantity,
    toggleSelect,
    selectAll,
    deselectAll,
    getProductStep,
    getProductMin
  } = useCart();

  const navigate = useNavigate();
  const handleClose = () => setIsSidebarOpen(false);

  // Calculate totals for selected items
  const selectedItems = cart.filter(item => item.selected);
  const subtotal = selectedItems.reduce((acc, item) => acc + (item.quantity * item.product.price), 0);
  const allSelected = cart.length > 0 && selectedItems.length === cart.length;

  const sidebarVariants = {
    closed: { x: '100%', transition: { type: 'spring', damping: 30, stiffness: 300 } },
    open: { x: 0, transition: { type: 'spring', damping: 30, stiffness: 300, staggerChildren: 0.1, delayChildren: 0.2 } }
  };

  const itemVariants = {
    closed: { opacity: 0, x: 20 },
    open: { opacity: 1, x: 0, transition: { duration: 0.4 } }
  };

  return (
    <AnimatePresence>
      {isSidebarOpen && (
        <>
          {/* Backdrop */}
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={handleClose}
            className="fixed inset-0 bg-[#4E342E]/40 backdrop-blur-[4px] z-[100] transition-all duration-500"
          />

          {/* Slide-out Sidebar */}
          <motion.div 
            variants={sidebarVariants}
            initial="closed"
            animate="open"
            exit="closed"
            className="fixed top-0 right-0 h-full w-full max-w-[480px] bg-[#FCF9F6] z-[101] shadow-[-20px_0_50px_rgba(78,52,46,0.15)] flex flex-col overflow-hidden"
          >
            
            {/* Header - Luxury Minimalist */}
            <div className="px-8 py-7 border-b border-[#F0E6DD] flex items-center justify-between bg-white/80 backdrop-blur-md sticky top-0 z-20">
              <div className="flex flex-col">
                <div className="flex items-center gap-3">
                  <span className="font-serif text-2xl text-[#4E342E] tracking-tight">Your Selection</span>
                  <span className="flex items-center justify-center min-w-[22px] h-[22px] px-1.5 bg-[#A68966] text-white rounded-full text-[10px] font-bold font-sans">
                    {cart.length}
                  </span>
                </div>
                <p className="text-[10px] uppercase tracking-[0.2em] text-[#8D6E63] mt-1 font-bold font-sans">Abirami Parryware Studio</p>
              </div>
              <motion.button 
                whileHover={{ rotate: 90, scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={handleClose}
                className="w-10 h-10 flex items-center justify-center rounded-full hover:bg-[#F5EFE9] text-[#4E342E] transition-colors bg-[#FDFBF9] border border-[#F0E6DD]"
              >
                <X className="w-5 h-5" />
              </motion.button>
            </div>

            {/* Cart Contents */}
            <div className="flex-1 overflow-y-auto px-8 py-8 custom-scrollbar">
              {cart.length === 0 ? (
                <motion.div 
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="h-full flex flex-col items-center justify-center text-center space-y-6"
                >
                  <div className="w-24 h-24 bg-[#F5EFE9] rounded-full flex items-center justify-center relative">
                    <ShoppingBag className="w-10 h-10 text-[#A68966] stroke-1" />
                    <motion.div 
                      animate={{ scale: [1, 1.2, 1] }}
                      transition={{ duration: 2, repeat: Infinity }}
                      className="absolute -top-1 -right-1 w-4 h-4 bg-[#4E342E] rounded-full"
                    />
                  </div>
                  <div>
                    <h3 className="font-serif text-2xl text-[#4E342E] mb-2">The Sanctuary is Empty</h3>
                    <p className="text-[#8D6E63] text-sm font-sans font-light max-w-[240px] leading-relaxed mx-auto">
                      Explore our collections and discover the perfect additions for your home.
                    </p>
                  </div>
                  <motion.button 
                    whileHover={{ scale: 1.05 }}
                    whileTap={{ scale: 0.95 }}
                    onClick={() => {
                      handleClose();
                      navigate('/catalog');
                    }}
                    className="flex items-center gap-2 group text-[#A68966] font-bold text-xs uppercase tracking-widest pt-4"
                  >
                    Explore Catalog
                    <ArrowRight className="w-4 h-4 transition-transform group-hover:translate-x-1" />
                  </motion.button>
                </motion.div>
              ) : (
                <>
                  {/* Select All Bar */}
                  <div className="flex items-center justify-between pb-6">
                    <button 
                      onClick={allSelected ? deselectAll : selectAll}
                      className="flex items-center gap-3 group px-4 py-2 rounded-full border border-[#F0E6DD] bg-white transition-all hover:border-[#A68966]/30"
                    >
                      <div className={`w-4 h-4 rounded-full border flex items-center justify-center transition-all duration-300 ${allSelected ? 'bg-[#4E342E] border-[#4E342E]' : 'border-[#D1C6BD] bg-white'}`}>
                        {allSelected && <CheckCircle2 className="w-3 h-3 text-white" strokeWidth={3} />}
                      </div>
                      <span className="text-[10px] font-bold uppercase tracking-widest text-[#4E342E]">
                        {allSelected ? 'Deselect All Items' : 'Select All Items'}
                      </span>
                    </button>
                  </div>

                  {/* Items List */}
                  <div className="space-y-6">
                    {cart.map((item) => {
                      const step = getProductStep(item.product);
                      const min = getProductMin(item.product);
                      
                      return (
                        <motion.div 
                          key={item.product.id}
                          variants={itemVariants}
                          className={`group relative bg-white rounded-3xl p-5 flex gap-5 shadow-[0_10px_30px_rgba(78,52,46,0.02)] border transition-all duration-500 ${item.selected ? 'border-[#A68966]/30 shadow-[0_15px_40px_rgba(166,137,102,0.08)]' : 'border-transparent'}`}
                        >
                          {/* Selection Toggle */}
                          <button 
                            onClick={() => toggleSelect(item.product.id)}
                            className="absolute top-4 left-4 z-10"
                          >
                            <div className={`w-4 h-4 rounded-full border flex items-center justify-center transition-all duration-300 ${item.selected ? 'bg-[#4E342E] border-[#4E342E]' : 'border-[#D1C6BD] bg-white shadow-sm'}`}>
                              {item.selected && <CheckCircle2 className="w-3 h-3 text-white" strokeWidth={3} />}
                            </div>
                          </button>

                          {/* Image */}
                          <div className="w-[110px] h-[110px] rounded-2xl overflow-hidden bg-[#FDFBF9] flex-shrink-0 relative border border-[#F5F0EB]">
                            {item.product.image && (
                              <img src={item.product.image} alt={item.product.name} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
                            )}
                            <div className="absolute inset-0 bg-[#4E342E]/5 group-hover:bg-transparent transition-colors" />
                          </div>

                          {/* Details */}
                          <div className="flex-1 flex flex-col justify-between py-0.5">
                            <div>
                              <div className="flex justify-between items-start gap-4">
                                <h3 className="text-[16px] font-serif text-[#4E342E] leading-tight line-clamp-1 group-hover:text-[#A68966] transition-colors uppercase tracking-tight">
                                  {item.product.name}
                                </h3>
                                <button 
                                  onClick={() => removeFromCart(item.product.id)}
                                  className="w-8 h-8 rounded-full flex items-center justify-center text-[#D1C6BD] hover:text-red-500 hover:bg-red-50 transition-all flex-shrink-0"
                                >
                                  <Trash2 size={16} />
                                </button>
                              </div>
                              <p className="text-[11px] text-[#A68966] mt-1 line-clamp-1 uppercase tracking-widest font-sans font-bold opacity-80">
                                {item.product.category || 'Premium Collection'}
                              </p>
                            </div>

                            <div className="flex items-center justify-between mt-4">
                              <div className="font-serif text-xl text-[#4E342E]">
                                <span className="text-[11px] font-sans font-bold tracking-widest text-[#8D6E63] mr-1 opacity-60">INR</span>
                                {item.product.price.toLocaleString('en-IN')}
                              </div>
                              
                              {/* Quantity Controls - Sleeker */}
                              <div className="h-9 p-0.5 flex items-center bg-[#FDFBF9] rounded-full border border-[#F0E6DD] overflow-hidden">
                                <motion.button 
                                  whileTap={{ scale: 0.9 }}
                                  onClick={() => {
                                    if (item.quantity <= min) removeFromCart(item.product.id);
                                    else updateQuantity(item.product.id, item.quantity - step);
                                  }}
                                  className="w-8 h-8 flex items-center justify-center text-[#8D6E63] hover:text-[#4E342E] rounded-full transition-colors"
                                >
                                  {item.quantity <= min ? <Trash2 size={12} strokeWidth={2.5} /> : <Minus size={12} strokeWidth={2.5} />}
                                </motion.button>
                                <div className="w-10 text-center text-[13px] font-bold text-[#4E342E] font-sans">
                                  {item.quantity}
                                </div>
                                <motion.button 
                                  whileTap={{ scale: 0.9 }}
                                  onClick={() => updateQuantity(item.product.id, item.quantity + step)}
                                  className="w-8 h-8 flex items-center justify-center text-[#8D6E63] hover:text-[#4E342E] rounded-full transition-colors"
                                >
                                  <Plus size={12} strokeWidth={2.5} />
                                </motion.button>
                              </div>
                            </div>
                          </div>
                        </motion.div>
                      );
                    })}
                  </div>
                </>
              )}
            </div>

            {/* Footer / Checkout - Premium Gradient */}
            {cart.length > 0 && (
              <div className="border-t border-[#F0E6DD] bg-white p-8 space-y-6">
                <div className="space-y-4">
                  <div className="flex justify-between items-center text-[10px] uppercase tracking-[0.2em] font-bold text-[#8D6E63]">
                    <span>Item Summary</span>
                    <span>{selectedItems.length} Selected</span>
                  </div>
                  <div className="flex justify-between items-end">
                    <span className="font-serif text-2xl text-[#4E342E]">Total Est.</span>
                    <div className="text-right">
                      <div className="font-serif text-3xl text-[#4E342E] tracking-tighter">
                        Γé╣{subtotal.toLocaleString('en-IN')}
                      </div>
                      <p className="text-[10px] text-[#A68966] font-bold font-sans uppercase tracking-widest mt-1">incl. luxury taxes</p>
                    </div>
                  </div>
                </div>

                <Link 
                  to="/checkout"
                  onClick={handleClose}
                  className={`block w-full py-5 text-white font-bold text-xs uppercase tracking-[0.3em] rounded-2xl shadow-xl transition-all duration-500 overflow-hidden relative group text-center ${
                    selectedItems.length === 0 
                      ? 'bg-[#F0E6DD] text-[#D1C6BD] pointer-events-none' 
                      : 'bg-[#4E342E] hover:shadow-[0_20px_40px_rgba(78,52,46,0.25)]'
                  }`}
                >
                  <span className="relative z-10 flex items-center justify-center gap-3">
                    Proceed to Checkout
                    <ArrowRight className="w-4 h-4 transition-transform group-hover:translate-x-1" />
                  </span>
                  <div className="absolute inset-0 bg-gradient-to-r from-[#4E342E] via-[#8D6E63] to-[#4E342E] translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-1000 ease-in-out opacity-20" />
                </Link>
              </div>
            )}
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
};

export default CartSidebar;

