        price: defaultPrices[i],
        mrp: defaultMRPs[i],
        image: finalImage,
        rating: 4.5 + (i * 0.1),
        reviews: 120 + (i * 35)
      };
    });
  };

  const products = getProducts();

  const displayTitle = categoryId.replace('faucet-', '').split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');

  return (
