                      >
                        Add to Cart
                      </button>
                    )}
                  </div>
                </div>
              </motion.div>
            );
          })}
        </div>
      </main>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowUpRight } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const categories = [
  { id: 0, title: 'Water Heater', bgImage: '/images/heater_new.png', desc: 'Instant & Storage Systems', path: '/water-heater' },
  { id: 1, title: 'Closet', bgImage: 'https://images.unsplash.com/photo-1584622650111-993a426fbf0a?auto=format&fit=crop&q=80', desc: 'Smart & Premium Designs', path: '/closet' },
  { id: 2, title: 'Basin', bgImage: '/images/basin.png', desc: 'Countertop & Wall Hung', path: '/basin' },
  { id: 3, title: 'Faucets', bgImage: '/images/faucet_new.png', desc: 'Elegant Chrome & Matte', path: '/faucets' },
  { id: 4, title: 'Chimney', bgImage: '/images/chimney.png', desc: 'Slanted & Island Models', path: '/chimney' },
  { id: 5, title: 'Tiles and Surface', bgImage: '/images/tiles.jpg', desc: 'Large Format & Marble', path: '/tiles-and-surface' }
];

const Products = () => {
  const [activeIndex, setActiveIndex] = useState(0);
  const navigate = useNavigate();

  // Unstoppable auto-play every 2000ms
  useEffect(() => {
    const interval = setInterval(() => {
      setActiveIndex((prev) => (prev + 1) % categories.length);
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  const getCardStyle = (index) => {
    const offset = (index - activeIndex + categories.length) % categories.length;

    if (offset === 0) {
      return { x: 0, y: 0, scale: 1, rotate: 0, zIndex: 30, opacity: 1 };
    } else if (offset === 1) {
      return { x: "50%", y: 30, scale: 0.85, rotate: 10, zIndex: 20, opacity: 1 };
    } else if (offset === 2) {
      return { x: "90%", y: 60, scale: 0.7, rotate: 20, zIndex: 10, opacity: 1 };
    } else if (offset === 5) {
      return { x: "-50%", y: 30, scale: 0.85, rotate: -10, zIndex: 20, opacity: 1 };
    } else if (offset === 4) {
      return { x: "-90%", y: 60, scale: 0.7, rotate: -20, zIndex: 10, opacity: 1 };
    } else {
      return { x: 0, y: -40, scale: 0.5, rotate: 0, zIndex: 0, opacity: 0 };
    }
  };

  return (
    <section className="py-24 max-w-[100vw] overflow-hidden bg-transparent">
      
      <div className="mb-20 flex flex-col items-center text-center relative z-40 px-6">
        <h2 className="text-4xl md:text-5xl lg:text-5xl font-sans font-bold text-cozy-900 mb-4 tracking-tight">Redefine Your Sanctuary</h2>
        <p className="text-xl md:text-2xl text-cozy-700 max-w-3xl font-serif italic leading-relaxed mx-auto text-center">
          Immerse yourself in our masterfully crafted collections. Elevate your daily rituals with uncompromising quality and breathtaking design. Explore our products below.
        </p>
      </div>

      <div 
        className="relative h-[450px] md:h-[600px] w-full max-w-5xl mx-auto flex items-center justify-center perspective-[1000px]"
      >
        {categories.map((cat, idx) => {
          const style = getCardStyle(cat.id);
          const isActive = style.zIndex === 30;

          return (
            <motion.div
              key={cat.id}
              className="absolute w-[280px] md:w-[380px] h-[400px] md:h-[500px] rounded-3xl overflow-hidden cursor-pointer shadow-[0_10px_40px_rgba(0,0,0,0.2)] bg-cozy-900 origin-bottom"
              initial={false}
              animate={{
                x: style.x,
                y: style.y,
                scale: style.scale,
                rotateZ: style.rotate,
                zIndex: style.zIndex,
                opacity: style.opacity
              }}
              transition={{
                type: 'spring',
                stiffness: 60,
                damping: 14,
                mass: 1
              }}
              onClick={() => {
                if (isActive) {
                  navigate(cat.path);
                } else {
                  setActiveIndex(cat.id);
                }
              }}
            >
              <div className="absolute inset-0 w-full h-full">
                <img 
                  src={cat.bgImage} 
                  alt={cat.title} 
                  className="w-full h-full object-cover rounded-3xl"
                  onError={(e) => { e.currentTarget.src = "https://images.unsplash.com/photo-1606709794025-a7b3dbd3269b?auto=format&fit=crop&q=80" }} // fallback if PNG was actually JPG
                />
              </div>

              <div className={`absolute inset-0 transition-opacity duration-700 ${isActive ? 'bg-gradient-to-t from-black/90 via-[#663b2f]/40 to-transparent' : 'bg-black/40'}`}></div>
              
              <div className={`absolute inset-x-0 bottom-0 p-8 flex flex-col justify-end transition-all duration-700 ${isActive ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-8'}`}>
                <p className="text-white/80 text-sm tracking-widest uppercase mb-2 font-medium">{cat.desc}</p>
                <h3 className="text-3xl md:text-4xl font-serif text-white mb-6 drop-shadow-lg">{cat.title}</h3>
                
                <div className="w-full border-t border-white/20 pt-4 flex items-center justify-between group">
                  <span className="text-white text-sm font-bold tracking-widest uppercase group-hover:text-cozy-200 transition-colors">Explore Now</span>
                  <div className="bg-white/30 border border-white/40 w-10 h-10 rounded-full backdrop-blur-md flex items-center justify-center group-hover:bg-white transition-all">
                    <ArrowUpRight className="w-5 h-5 text-white group-hover:text-cozy-900" />
                  </div>
                </div>
              </div>
            </motion.div>
          );
        })}
      </div>
    </section>
  );
};

export default Products;

import React from 'react';
import { motion } from 'framer-motion';
import { ShoppingCart, Star, Check, ArrowLeft, Trash2, Plus, Minus } from 'lucide-react';
import { Link } from 'react-router-dom';

const imageUrls = [
  "/images/faucets/quattro_new_1.jpg",
  "/images/faucets/quattro_new_2.jpg",
  "/images/faucets/quattro_new_3.jpg",
  "/images/faucets/quattro_new_4.jpg",
  "/images/faucets/quattro_new_5.jpg"
];

export default function QuattroCollection() {
  const [cart, setCart] = useState([]);

  const getProducts = () => {
    const defaultPrices = [3800, 3200, 4200, 4500, 5900];
    const defaultMRPs = [5500, 4800, 5800, 6200, 8100];
    const names = [
      'Quattro Wall Mounted Faucet',
      'Quattro Single Lever Basin Mixer',
      'Quattro Black Precision Mixer',
      'Quattro Tall Basin Mixer',
      'Quattro Linear Sensor Tap'
    ];
    
    return [0, 1, 2, 3, 4].map((i) => ({
      id: `faucet-quattro-${i+1}`,
      name: names[i],
      description: `Experience uncompromising water efficiency and elegant modern geometric design perfectly tailored for your luxury architectural needs. Built with extreme precision.`,
      price: defaultPrices[i],
      mrp: defaultMRPs[i],
      image: imageUrls[i],
      rating: 4.5 + (i * 0.1),
      reviews: 120 + (i * 35)
    }));
  };

  const products = getProducts();

  const handleAddToCart = (product) => {
    if (!cart.find(item => item.product.id === product.id)) {
      setCart([...cart, { product, quantity: 1 }]);
    }
  };

  const handleIncrease = (productId) => {
    setCart(cart.map(item => 
      item.product.id === productId ? { ...item, quantity: item.quantity + 1 } : item
    ));
  };

  const handleDecrease = (productId) => {
    setCart(cart.map(item => {
      if (item.product.id === productId) {
        if (item.quantity === 1) return null;
        return { ...item, quantity: item.quantity - 1 };
      }
      return item;
    }).filter(Boolean));
  };

  const handleRemoveFromCart = (productId) => {
    setCart(cart.filter(item => item.product.id !== productId));
  };

  return (
    <div 
      className="min-h-screen font-sans w-full overflow-y-auto bg-transparent relative"
    >
      {/* Ambient Top Glow */}
      <div className="absolute top-0 inset-x-0 h-[400px] bg-gradient-to-b from-[#A68966]/10 to-transparent pointer-events-none"></div>
      {/* Amazon Style Header but light themed to match Basin styling */}
      {/* Glassmorphic Header */}
      <header className="bg-white/40 backdrop-blur-md h-[70px] flex items-center justify-between px-6 text-gray-900 sticky top-0 z-50 border-b border-gray-200/50 shadow-sm transition-all duration-300">
        <div className="flex items-center gap-4">
          <Link to="/faucets" className="hover:text-gray-600 transition-colors p-2 rounded-full hover:bg-gray-100">
            <ArrowLeft className="w-6 h-6" />
          </Link>
          <h1 className="text-lg md:text-xl font-bold tracking-tight">Quattro Collection</h1>
        </div>
        <div className="relative flex items-center cursor-pointer p-2 rounded-full hover:bg-gray-100 transition-colors">
          <ShoppingCart className="w-7 h-7 text-gray-700" />
          {cart.length > 0 && (
            <span className="absolute top-0 right-0 bg-[#E33939] text-white font-bold text-[10px] rounded-full w-[18px] h-[18px] flex items-center justify-center shadow-md">
              {cart.reduce((total, item) => total + item.quantity, 0)}
            </span>
          )}
        </div>
      </header>

      <main className="max-w-[1400px] mx-auto p-4 md:p-8 pb-16 mt-4 relative z-10">
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 xl:gap-8 justify-center">
          {products.map((product, i) => {
            const cartItem = cart.find(item => item.product.id === product.id);
            return (
              <motion.div 
                key={product.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.4, delay: i * 0.1 }}
                className="bg-white rounded-[28px] p-3 shadow-sm hover:shadow-lg flex flex-col transition-all duration-300 border border-gray-100/50"
              >
                {/* Image Container */}
                <div className="relative w-full h-[260px] rounded-[20px] overflow-hidden bg-gray-50 flex items-center justify-center mb-1 group">
                  <img 
                    src={product.image} 
                    alt={product.name} 
                    className="h-full w-full object-cover transition-transform duration-700 group-hover:scale-[1.03]"
                  />
                  
                  {/* Dynamic Badges */}
                  <div className="absolute top-3 left-3 bg-white/95 backdrop-blur-md text-[#222222] text-[12px] font-bold px-3 py-1.5 rounded-full flex items-center gap-1.5 shadow-[0_2px_8px_rgba(0,0,0,0.08)]">
                    <Star className="w-[12px] h-[12px] fill-[#F5A623] text-[#F5A623]" /> Prime Pick
                  </div>

                  {/* Dot Indicators */}
                  <div className="absolute bottom-3 inset-x-0 flex justify-center gap-1.5">
                    <div className="w-[6px] h-[6px] rounded-full bg-white"></div>
                    <div className="w-[6px] h-[6px] rounded-full bg-white/50"></div>
                    <div className="w-[6px] h-[6px] rounded-full bg-white/50"></div>
                    <div className="w-[6px] h-[6px] rounded-full bg-white/50"></div>
                  </div>
                </div>

                {/* Content Container */}
                <div className="px-2 pt-4 pb-2 flex flex-col flex-grow">
                  {/* Price Row */}
                  <div className="flex items-baseline gap-2 mb-1">
                    <span className="text-[22px] font-extrabold text-[#111111] tracking-tight">
                      Γé╣{product.price.toLocaleString('en-IN')}
                    </span>
                    <span className="text-[13px] text-gray-500 font-medium tracking-wide">
                      List price
                    </span>
                  </div>

                  {/* Title Row */}
                  <h2 className="text-[15px] font-medium text-[#222222] leading-snug truncate whitespace-nowrap overflow-hidden text-ellipsis mb-5">
                    <span className="font-bold">{product.name.split(' ')[0]}</span> ΓÇó {product.name.substring(product.name.indexOf(' ') + 1) || product.description}
                  </h2>
                  
                  <div className="h-[1px] w-full bg-gray-100 mb-4"></div>
                  
                  {/* Specs Row */}
                  <div className="flex items-center text-[13px] text-gray-600 font-medium mb-4">
                    <div className="flex flex-1 items-center justify-center gap-2 border-r border-gray-100">
                      <Star className="w-[16px] h-[16px] text-gray-400" />
                      <span>{product.rating} Rating</span>
                    </div>
                    <div className="flex flex-1 items-center justify-center gap-2">
                      <svg className="w-[16px] h-[16px] text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" /></svg>
                      <span>1 Unit</span>
                    </div>
                  </div>

                  <div className="h-[1px] w-full bg-gray-100 mb-4"></div>

                  <div className="flex items-center justify-between text-[13px] text-gray-500 mb-6">
                    <div>By ΓÇó <span className="text-gray-900 font-semibold underline underline-offset-2">Parryware</span></div>
                    <div>2 days ago</div>
                  </div>

                  {/* Buttons */}
                  <div className="mt-auto">
                    {cartItem ? (
                      <div className="w-full h-[52px] flex items-center justify-between border-[1px] border-gray-800 rounded-full overflow-hidden bg-white text-gray-900 shadow-sm">
                        <button 
                          onClick={() => cartItem.quantity === 1 ? handleRemoveFromCart(product.id) : handleDecrease(product.id)} 
                          className="h-full px-5 hover:bg-gray-100 transition-colors flex items-center justify-center"
                        >
                          {cartItem.quantity === 1 ? 
                            <Trash2 className="w-[18px] h-[18px]" strokeWidth={2} /> : 
                            <Minus className="w-[18px] h-[18px]" strokeWidth={2.5} />
                          }
                        </button>
                        <span className="font-bold text-[16px] px-4">{cartItem.quantity}</span>
                        <button 
                          onClick={() => handleIncrease(product.id)} 
                          className="h-full px-5 bg-gray-50 hover:bg-gray-100 transition-colors flex items-center justify-center border-l border-gray-200"
                        >
                          <Plus className="w-[20px] h-[20px]" strokeWidth={2.5} />
                        </button>
                      </div>
                    ) : (
                      <button
                        onClick={() => handleAddToCart(product)}
                        className="w-full h-[52px] rounded-full text-[15px] font-semibold tracking-wide transition-all duration-300 flex items-center justify-center gap-2 bg-gradient-to-b from-[#2a2a2a] to-[#0f0f0f] text-white shadow-md transform hover:scale-[1.01]"
                      >
                        Add to Cart
                      </button>
                    )}
                  </div>
                </div>
              </motion.div>
            );
          })}
        </div>
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { Mail, Lock, AlertCircle, CheckCircle, Eye, EyeOff, X } from 'lucide-react';
import { Link, useNavigate } from 'react-router-dom';
import { GoogleLogin } from '@react-oauth/google';
import { jwtDecode } from 'jwt-decode';

import { useAuth } from '../context/AuthContext';

const SignIn = () => {
  const navigate = useNavigate();
  const { login: authLogin } = useAuth();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  React.useEffect(() => {
    const checkServer = async () => {
      try {
        const res = await fetch('http://127.0.0.1:5000/api/health');
        if (!res.ok) throw new Error();
        console.log('--- Server Protocol Online ---');
      } catch (err) {
        setError('CRITICAL: Server Offline. Please start backend terminal.');
      }
    };
    checkServer();
  }, []);

  const handleGoogleSuccess = async (credentialResponse) => {
    setError('');
    setSuccess('Verified. Identifying Records...');
    
    try {
      const decoded = jwtDecode(credentialResponse.credential);
      setEmail(decoded.email || '');
      setPassword('ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó'); 

      const response = await fetch('http://127.0.0.1:5000/api/auth/google', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ credential: credentialResponse.credential })
      });
      const data = await response.json();
      
      if (data.success) {
        setSuccess('SIGNED IN SUCCESSFULLY!');
        authLogin(data.user, data.token);
        
        // Wait 2 seconds so the user can see the success message
        setTimeout(() => {
          navigate('/');
        }, 2000);
      } else {
        setError(data.message || 'Google Auth Failed');
        setSuccess('');
      }
    } catch (err) {
      setError('Server Error: Connection Failed');
      setSuccess('');
    }
  };

  const handleManualLogin = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('Checking Registry...');
    
    try {
      const response = await fetch('http://127.0.0.1:5000/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password })
      });
      const data = await response.json();
      
      if (data.success) {
        setSuccess('SIGNED IN SUCCESSFULLY!');
        authLogin(data.user, data.token);
        
        setTimeout(() => {
          navigate('/');
        }, 2000);
      } else {
        setError(data.message || 'Invalid Credentials');
        setSuccess('');
      }
    } catch (err) {
      setError('Server Error: Access Timed Out');
      setSuccess('');
    }
  };

  const handleForgotPassword = (e) => {
    e.preventDefault();
    if (!email) {
      setError('Enter Email Handle First');
      return;
    }
    setError('');
    setSuccess(`Reset link sent to ${email}`);
  };

  return (
    <div className="min-h-screen w-full flex items-start justify-center px-4 relative pt-24 md:pt-32 pb-20 overflow-hidden" style={{ fontFamily: "'Times New Roman', Times, serif" }}>

      <div className="authenticate-box z-10 p-6 flex flex-col items-center shadow-xl">
        <div className="text-center mb-4">
          <h2 className="font-serif-elegant text-2xl text-[#3E2723] mb-1 font-bold tracking-tight">
            Sign In
          </h2>
          <div className="w-8 h-[2px] bg-[#3E2723]/20 mx-auto mb-2" />
          <p className="luxury-label">Registry Access</p>
        </div>

        {error && (
          <div className="w-full mb-4 p-3 bg-red-50 border border-red-200 rounded-lg flex items-center gap-3 text-red-700 text-[10px] font-black uppercase tracking-widest leading-tight">
            <AlertCircle size={14} className="shrink-0" /> {error.includes('Google') || error.includes('Token') ? 'GOOGLE AUTH SYSTEM ERROR' : error}
          </div>
        )}

        {success && (
          <div className="w-full mb-4 p-4 bg-green-50 border border-green-200 rounded-xl flex items-center gap-3 text-green-800 text-[11px] font-black uppercase tracking-widest leading-tight text-center">
            <CheckCircle size={16} className="shrink-0" /> {success}
          </div>
        )}

        <div className="w-full mb-4">
          <GoogleLogin
            onSuccess={handleGoogleSuccess}
            onError={() => setError('Google Identity Error: System Offline')}
            theme="filled_black"
            size="large"
            shape="rectangular"
          />
        </div>

        <div className="w-full relative mb-4 text-center">
          <div className="absolute inset-0 flex items-center">
            <div className="w-full border-t border-[#3E2723]/10"></div>
          </div>
          <span className="relative px-3 bg-[#FCFBF9] text-[#3E2723]/30 text-[8px] uppercase tracking-[0.5em] font-black italic">OR</span>
        </div>

        <form className="w-full space-y-3" onSubmit={handleManualLogin}>
          <div className="space-y-0.5">
            <label className="luxury-label">Email Handle</label>
            <input 
              type="email" 
              required
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="id@residence.com"
              className="w-full glass-input-premium"
            />
          </div>

          <div className="space-y-0.5 relative">
            <div className="flex justify-between items-center">
              <label className="luxury-label">Passphrase</label>
              <button 
                type="button"
                onClick={handleForgotPassword}
                className="text-[9px] uppercase tracking-widest font-black text-[#A68966] hover:text-[#3E2723] transition-colors"
              >
                Lost Access?
              </button>
            </div>
            <div className="relative group">
              <input 
                type={showPassword ? "text" : "password"} 
                required
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                className="w-full glass-input-premium pr-10"
                style={{ WebkitTextSecurity: showPassword ? 'none' : 'disc' }}
              />
              <button
                type="button"
                onClick={() => {
                  console.log('Toggling Password:', !showPassword);
                  setShowPassword(!showPassword);
                }}
                className="absolute right-0 top-1/2 -translate-y-1/2 p-2 text-[#3E2723] hover:text-black transition-colors z-20 cursor-pointer"
                title={showPassword ? "Hide password" : "Show password"}
              >
                {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
              </button>
            </div>
          </div>

          <button 
            type="submit"
            className="w-full bg-[#3E2723] text-white py-4 rounded-lg font-black uppercase tracking-[0.6em] text-[10px] shadow-2xl hover:bg-black transition-all active:scale-95"
          >
            Authenticate
          </button>
        </form>

        <div className="mt-8 text-center pt-6 border-t border-[#3E2723]/5 w-full">
          <p className="text-[#3E2723]/40 text-[10px] font-black uppercase tracking-widest">
            New Identity? {' '}
            <Link to="/signup" className="text-[#3E2723] hover:underline underline-offset-8 decoration-2">Register Here</Link>
          </p>
        </div>
      </div>
    </div>
  );
};

export default SignIn;

